VALUES
  ('social-worker-moex-06300', 'social-worker', 'social-worker-moex-104-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '發生衝突是組織中難以避免的現象，衝突可能帶來負面也可能帶來正面的影響。主張「衝突對一個團體 是絕對必要的，沒有衝突的團體可能是冷漠、疏離的，對於要求改變與創新的需求無所回應。管理者不 但要接受衝突，甚且要鼓勵組織有適度的衝突，以便能保持團體的自省能力和改變的動力。」這是下列 那一種觀點？', '["衝突的傳統觀點", "衝突的人際關係觀點", "衝突的互動觀點", "衝突的人文關懷觀點"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "55945ae1d825", "answer_pdf_sha1": "a8f75b55a517", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06301', 'social-worker', 'social-worker-moex-104-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '工作分析是人力資源管理的主要功能之一，採用「工作分析者選擇具有代表性的員工，針對工作的內容 進行訪談，而此一方法比較能深入了解員工內心的想法。」此工作分析資訊蒐集方法稱為：', '["觀察法", "問卷調查法", "工作日記法", "訪談法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "55945ae1d825", "answer_pdf_sha1": "a8f75b55a517", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06302', 'social-worker', 'social-worker-moex-104-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '員工訓練的種類中，員工以公假的方式，暫時離開他的工作崗位去接受訓練的訓練方式稱為：', '["工作外訓練（Off the Job Training）", "工作中訓練（On the Job Training）", "自我訓練（Self Training）", "職前訓練（Orientation）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "55945ae1d825", "answer_pdf_sha1": "a8f75b55a517", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06303', 'social-worker', 'social-worker-moex-104-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '1963 年由亞當斯所提出，認為「個人的工作動機乃是基於和自己相同地位的同事間比較所產生的，員工 會拿自己對於工作的付出和報酬跟其他員工之付出與報酬做一比較，並且會試圖修正不公平的狀態。」 此激勵理論稱為：', '["目標設定理論", "期望理論", "雙因子理論", "公平理論"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "55945ae1d825", "answer_pdf_sha1": "a8f75b55a517", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06304', 'social-worker', 'social-worker-moex-104-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在績效考核中，考評者會因某種特殊事件或工作上表現不理想，而對受評者之能力產生低估之偏失的現 象稱為：', '["刻板印象（stereotyping）", "尖角效應（horn effect）", "盲點效應（blindness effect）", "對比效應（contrast effect）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "55945ae1d825", "answer_pdf_sha1": "a8f75b55a517", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06305', 'social-worker', 'social-worker-moex-104-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '根據Hawkins和Shohet（1989）所建議的四種主要督導類型中，督導者視受督導者為學生，督導者在訓 練過程中扮演教育角色，並須負責受督導部分實務工作的督導類型是：', '["諮詢式督導（consulting supervision）", "管理式督導（managerial supervision）", "訓練式督導（training supervision）", "師徒式督導（tutorial supervision）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "55945ae1d825", "answer_pdf_sha1": "a8f75b55a517", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06306', 'social-worker', 'social-worker-moex-104-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '根據Flanagan（2000）的主張，所有組織的慈善募款活動，想要成功的話，下列那一項指導原則是錯誤的：', '["提供捐款者單一的選擇機會", "募款工作要遵守一定的倫理規範", "要與最佳贊助人建立長期而穩定的關係", "建立既深且廣的贊助人群眾基礎"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "55945ae1d825", "answer_pdf_sha1": "a8f75b55a517", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06307', 'social-worker', 'social-worker-moex-104-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '下列有關組織預算的敘述何者正確？', '["一項預算可以協助我們規劃與連結來年的相關活動", "預算要能夠有效地發揮功能，必須經過仔細的構思，但不須經過董（理）事會核備", "預算並非以量化的數據顯示在一定時間內組織所計畫的活動", "迫使每個部門以零為基礎，重新預估在新的預算其所需要的經費之預算法稱為功能性預算法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "55945ae1d825", "answer_pdf_sha1": "a8f75b55a517", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06308', 'social-worker', 'social-worker-moex-104-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '下列有關目標管理對組織的效益之敘述何者正確？', '["實施目標管理並不會實現組織的願景", "實施目標管理可以展現組織的透明管理", "實施目標管理並不會發揮組織的團隊合作", "實施目標管理並不會提升組織與個人價值"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "55945ae1d825", "answer_pdf_sha1": "a8f75b55a517", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06309', 'social-worker', 'social-worker-moex-104-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '無論是政府或非營利部門，績效監測已經是現代化組織經營管理上重要的一環，下列那一項並非是績效 監測的功能？', '["透明", "責信", "治療", "預防"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "55945ae1d825", "answer_pdf_sha1": "a8f75b55a517", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
